class VideoEntry {
  final List<String> topics;
  final String title;
  final String url;
  final String length;
  final String publishedDate;
  final String notes;

  const VideoEntry({
    required this.topics,
    required this.title,
    required this.url,
    required this.length,
    required this.publishedDate,
    this.notes = '',
  });

  String get youtubeId {
    final uri = Uri.parse(url);
    return uri.queryParameters['v'] ?? '';
  }
}

